function title(word) {
  let line = '--------------------------------------'
  line = line.slice(Math.floor(word.length / 2))
  let extra = "", extraA = ""
  if (word.length / 2 == Math.floor(word.length / 2)) { extra = '-' } else { extraA = '-' }
  return line + extra + extraA + ' ' + word + ' ' + line + extra
}

